from typing import TypedDict, Literal
from langgraph.graph import StateGraph, END
from langchain_openai import ChatOpenAI
from langchain_core.prompts import ChatPromptTemplate
from langchain_core.output_parsers import StrOutputParser

class DocState(TypedDict):
    raw_text: str
    doc_type: str
    result: str

llm = ChatOpenAI(model="claude-sonnet-5", temperature=0)
parser = StrOutputParser()

def classify_doc(state: DocState) -> DocState:
    chain = (
        ChatPromptTemplate.from_template(
            "Classify as exactly one word — legal, financial, or technical: {raw_text}"
        ) | llm | parser
    )
    doc_type = chain.invoke({"raw_text": state["raw_text"]}).strip().lower()
    return {"doc_type": doc_type}

# Router: reads state and returns the name of the next node
def route_by_type(state: DocState) -> Literal["legal_handler", "financial_handler", "technical_handler", "default_handler"]:
    mapping = {
        "legal": "legal_handler",
        "financial": "financial_handler",
        "technical": "technical_handler",
    }
    return mapping.get(state["doc_type"], "default_handler")

def legal_handler(state: DocState) -> DocState:
    chain = ChatPromptTemplate.from_template("Summarise legal obligations: {raw_text}") | llm | parser
    return {"result": chain.invoke(state)}

def financial_handler(state: DocState) -> DocState:
    chain = ChatPromptTemplate.from_template("Extract financial figures: {raw_text}") | llm | parser
    return {"result": chain.invoke(state)}

def technical_handler(state: DocState) -> DocState:
    chain = ChatPromptTemplate.from_template("List technical requirements: {raw_text}") | llm | parser
    return {"result": chain.invoke(state)}

def default_handler(state: DocState) -> DocState:
    return {"result": f"Unrecognised document type '{state['doc_type']}' — no specialist handler."}

graph = StateGraph(DocState)
for name, fn in [("classify_doc", classify_doc), ("legal_handler", legal_handler),
                 ("financial_handler", financial_handler), ("technical_handler", technical_handler),
                 ("default_handler", default_handler)]:
    graph.add_node(name, fn)

graph.set_entry_point("classify_doc")
# add_conditional_edges wires the router; each branch value maps to a node name
graph.add_conditional_edges("classify_doc", route_by_type)
for handler in ["legal_handler", "financial_handler", "technical_handler", "default_handler"]:
    graph.add_edge(handler, END)

chain = graph.compile()
result = chain.invoke({"raw_text": "This agreement obliges Acme to deliver by Q1 2027.", "doc_type": "", "result": ""})
print(result["doc_type"], "->", result["result"][:60])

from typing import TypedDict, Literal
from langgraph.graph import StateGraph, END
from langchain_openai import ChatOpenAI
from langchain_core.output_parsers import StrOutputParser
from langchain_core.prompts import ChatPromptTemplate
from pydantic import BaseModel

llm = ChatOpenAI(model="claude-sonnet-5", temperature=0)

class RouteDecision(BaseModel):
    route: Literal["simple", "complex", "escalate"]
    reason: str

class TicketState(TypedDict):
    ticket: str
    route: str
    reason: str
    response: str

structured_llm = llm.with_structured_output(RouteDecision)

def route_ticket(state: TicketState) -> TicketState:
    decision: RouteDecision = structured_llm.invoke(
        f"Route this support ticket to 'simple' (FAQ answer), 'complex' (needs investigation), "
        f"or 'escalate' (safety/legal). Return route and reason. Ticket: {state['ticket']}"
    )
    return {"route": decision.route, "reason": decision.reason}

def router(state: TicketState) -> Literal["simple_reply", "investigate", "escalate_to_human"]:
    return {"simple": "simple_reply", "complex": "investigate", "escalate": "escalate_to_human"}[state["route"]]

def simple_reply(state: TicketState) -> TicketState:
    return {"response": "Auto-reply: please check our FAQ at https://example.com/faq"}

def investigate(state: TicketState) -> TicketState:
    chain = ChatPromptTemplate.from_template("Write a detailed response to: {ticket}") | llm | StrOutputParser()
    return {"response": chain.invoke(state)}

def escalate_to_human(state: TicketState) -> TicketState:
    return {"response": f"Escalated to human agent. Reason: {state['reason']}"}

graph = StateGraph(TicketState)
for name, fn in [("route_ticket", route_ticket), ("simple_reply", simple_reply),
                 ("investigate", investigate), ("escalate_to_human", escalate_to_human)]:
    graph.add_node(name, fn)

graph.set_entry_point("route_ticket")
graph.add_conditional_edges("route_ticket", router)
for node in ["simple_reply", "investigate", "escalate_to_human"]:
    graph.add_edge(node, END)

app = graph.compile()
r = app.invoke({"ticket": "My invoice shows incorrect amounts.", "route": "", "reason": "", "response": ""})
print(r["route"], "->", r["response"][:80])

from typing import TypedDict, Literal
from langgraph.graph import StateGraph, END
from langchain_openai import ChatOpenAI
from langchain_core.prompts import ChatPromptTemplate
from langchain_core.output_parsers import StrOutputParser

llm = ChatOpenAI(model="claude-sonnet-5", temperature=0)
parser = StrOutputParser()

class ReviewState(TypedDict):
    document: str
    draft: str
    feedback: str
    revision_count: int
    final: str

def draft(state: ReviewState) -> ReviewState:
    chain = ChatPromptTemplate.from_template("Write a brief summary of: {document}") | llm | parser
    return {"draft": chain.invoke(state), "revision_count": state.get("revision_count", 0)}

def review(state: ReviewState) -> ReviewState:
    chain = (
        ChatPromptTemplate.from_template(
            "Review this summary. If good, say APPROVED. If not, say REVISE and give one improvement: {draft}"
        ) | llm | parser
    )
    return {"feedback": chain.invoke(state)}

def revise(state: ReviewState) -> ReviewState:
    chain = (
        ChatPromptTemplate.from_template("Revise the summary based on this feedback: {feedback}\n\nOriginal: {draft}")
        | llm | parser
    )
    return {"draft": chain.invoke(state), "revision_count": state["revision_count"] + 1}

def finalise(state: ReviewState) -> ReviewState:
    return {"final": state["draft"]}

def should_revise(state: ReviewState) -> Literal["revise", "finalise"]:
    # Stop if approved or if we've exceeded the revision limit
    if "APPROVED" in state["feedback"].upper():
        return "finalise"
    if state["revision_count"] >= 3:
        return "finalise"  # give up after 3 revisions
    return "revise"

graph = StateGraph(ReviewState)
for name, fn in [("draft", draft), ("review", review), ("revise", revise), ("finalise", finalise)]:
    graph.add_node(name, fn)

graph.set_entry_point("draft")
graph.add_edge("draft", "review")
graph.add_conditional_edges("review", should_revise, {"revise": "revise", "finalise": "finalise"})
graph.add_edge("revise", "review")   # loop back
graph.add_edge("finalise", END)

chain = graph.compile()
result = chain.invoke({"document": "Annual report 2026.", "draft": "", "feedback": "", "revision_count": 0, "final": ""})
print(f"Revisions: {result['revision_count']}, Final: {result['final'][:60]}")

