from typing import TypedDict, Literal
from langgraph.graph import StateGraph, END
from langchain_openai import ChatOpenAI
from langchain_core.output_parsers import StrOutputParser
from langchain_core.prompts import ChatPromptTemplate

llm = ChatOpenAI(model="claude-sonnet-5", temperature=0)
parser = StrOutputParser()

class State(TypedDict):
    text: str
    category: str
    urgency: str
    response: str

def classify(state: State) -> State:
    result = (ChatPromptTemplate.from_template("Category (legal/financial): {text}") | llm | parser).invoke(state)
    return {"category": result.strip().lower()}

def assess_urgency(state: State) -> State:
    result = (ChatPromptTemplate.from_template("Urgency (high/low) of this {category} matter: {text}") | llm | parser).invoke(state)
    return {"urgency": result.strip().lower()}

# First router: by category
def route_category(state: State) -> Literal["legal_urgency", "financial_urgency"]:
    return "legal_urgency" if state["category"] == "legal" else "financial_urgency"

# Second routers: by urgency within each category
def route_legal_urgency(state: State) -> Literal["urgent_legal", "standard_legal"]:
    return "urgent_legal" if "high" in state["urgency"] else "standard_legal"

def route_financial_urgency(state: State) -> Literal["urgent_financial", "standard_financial"]:
    return "urgent_financial" if "high" in state["urgency"] else "standard_financial"

# Leaf nodes
def urgent_legal(state: State) -> State:
    return {"response": "URGENT LEGAL: escalate to counsel immediately"}

def standard_legal(state: State) -> State:
    return {"response": "Standard legal review queued"}

def urgent_financial(state: State) -> State:
    return {"response": "URGENT FINANCIAL: alert CFO"}

def standard_financial(state: State) -> State:
    return {"response": "Standard financial review queued"}

graph = StateGraph(State)
for name, fn in [("classify", classify), ("legal_urgency", assess_urgency),
                 ("financial_urgency", assess_urgency),
                 ("urgent_legal", urgent_legal), ("standard_legal", standard_legal),
                 ("urgent_financial", urgent_financial), ("standard_financial", standard_financial)]:
    graph.add_node(name, fn)

graph.set_entry_point("classify")
graph.add_conditional_edges("classify", route_category)
graph.add_conditional_edges("legal_urgency", route_legal_urgency)
graph.add_conditional_edges("financial_urgency", route_financial_urgency)
for leaf in ["urgent_legal", "standard_legal", "urgent_financial", "standard_financial"]:
    graph.add_edge(leaf, END)

app = graph.compile()
r = app.invoke({"text": "Immediate breach of contract notice served.", "category": "", "urgency": "", "response": ""})
print(r["response"])

